import Vue from "vue";
import VueRouter from "vue-router";
import App from "./App.vue";
import Therapy from "./Therapy.vue";
import Fees from "./Fees.vue";
import Founder from "./Founder.vue";
// import Therapy from "./components/Therapy.vue";
// import HomePage from "./components/HomePage.vue";
// import Welcome from "./components/Welcome.vue";
// import WaysToWork from "./components/WaysToWork.vue";
// import Contact from "./components/Contact.vue";

Vue.config.productionTip = false;
Vue.use(VueRouter);

const routes = [
  { path: "/", component: App },
  { path: "/therapy", component: Therapy },
  { path: "/fees", component: Fees },
  { path: "/founder", component: Founder },
  { path: "/home", component: App },
  { path: "/welcome", component: App },
  { path: "/offerings", component: App },
  { path: "/contact", component: App },
  // { path: "/:catchAll(.*)", component: App },
];

const router = new VueRouter({
  mode: "history",
  routes,
  scrollBehavior(to, from, savedPosition) {
    if (to.hash) {
      return {
        selector: to.hash,
        behavior: "smooth",
      };
    }
    if (savedPosition) {
      return savedPosition;
    } else {
      return { x: 0, y: 0 };
    }
  },
});

new Vue({
  router,
}).$mount("#app");
